('5277bd96-9006-497a-b694-a46dfb8ddaab','7157b361-b8c6-4577-b6ca-77c73f68de3d','SELECT submission_date, COUNT(DISTINCT contact) AS registrations, COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END) AS attended, ROUND(SAFE_DIVIDE(COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END), COUNT(DISTINCT contact)) * 100, 2) AS rta_percent FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE submission_date BETWEEN DATE ''2026-01-01'' AND CURRENT_DATE() GROUP BY submission_date ORDER BY submission_date ASC LIMIT 1000;SELECT branch, programme, EXTRACT(YEAR FROM submission_date) AS year, EXTRACT(MONTH FROM submission_date) AS month, COUNT(DISTINCT contact) AS registrations, COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END) AS attended, ROUND(SAFE_DIVIDE(COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END), COUNT(DISTINCT contact)) * 100, 2) AS rta_percent FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE submission_date BETWEEN DATE ''2026-01-01'' AND CURRENT_DATE() GROUP BY branch, programme, year, month ORDER BY year, month, branch, programme LIMIT 1000
;
